    "howto.cat.communication": "Kommunikation",
    "howto.cat.communication.desc": "Kontakter, moten, RFI:er, korrespondens och samarbete i realtid.",
    "howto.cat.controls": "Styrning och BI",
    "howto.cat.controls.desc": "Projektstyrning, instrumentpaneler och baslinjeglimt.",
    "howto.cat.coordination": "Modellsamordning",
    "howto.cat.coordination.desc": "Federera modeller, hitta kollisioner och kontrollera dem mot krav.",
    "howto.cat.cost_control": "Kostnadsstyrning och risk",
    "howto.cat.cost_control.desc": "Folj budget mot utfall, jamna ut resurser och kvantifiera risk.",
    "howto.cat.cost_data": "Kostnadsdata",
    "howto.cat.cost_data.desc": "Katalogerna, sammansattningarna och riktvardena som dina priser kommer fran.",
